			AgentSession struct {
				ID      string `json:"id"`
				Harness string `json:"harness"`
				Status  string `json:"status"`
			} `json:"agentSession"`
		} `json:"data"`
	}
	if err := json.Unmarshal(body2, &resp2); err != nil {
		t.Fatalf("agentSession(id): invalid JSON: %v", err)
