import type { PageLoad } from './$types';
import { createClient } from '$lib/gql/client';
import { gql } from 'graphql-request';

const SESSIONS_QUERY = gql`
	query AgentSessions($first: Int, $projectId: ID!) {
		agentSessions(first: $first) {
			edges {
				node {
					id
					projectId
					beadId
					workerId
					harness
					model
					effort
					status
					startedAt
					endedAt
					durationMs
					cost
					billingMode
					tokens {
						prompt
						completion
						total
						cached
					}
					outcome
					detail
				}
				cursor
			}
			pageInfo {
				hasNextPage
				endCursor
			}
			totalCount
		}
		sessionsCostSummary(projectId: $projectId) {
			cashUsd
			cashSessionCount
			subscriptionEquivUsd
			subscriptionSessionCount
			localSessionCount
			localEstimatedUsd
		}
	}
`;

export const SESSION_DETAIL_QUERY = gql`
	query AgentSessionDetail($id: ID!) {
		agentSession(id: $id) {
			id
			prompt
			response
			stderr
		}
	}
`;

interface TokenUsage {
	prompt: number | null;
	completion: number | null;
	total: number | null;
	cached: number | null;
}

export interface SessionNode {
	id: string;
	projectId: string;
	beadId: string | null;
	workerId: string | null;
	harness: string;
	model: string;
	effort: string;
	status: string;
	startedAt: string;
	endedAt: string | null;
	durationMs: number;
	cost: number | null;
	billingMode: 'paid' | 'subscription' | 'local';
	tokens: TokenUsage | null;
	outcome: string | null;
	detail: string | null;
	prompt?: string | null;
	response?: string | null;
	stderr?: string | null;
}

interface SessionEdge {
	node: SessionNode;
	cursor: string;
}

interface SessionConnection {
	edges: SessionEdge[];
	pageInfo: { hasNextPage: boolean; endCursor: string | null };
	totalCount: number;
}

interface SessionsResult {
	agentSessions: SessionConnection;
	sessionsCostSummary: {
		cashUsd: number;
		cashSessionCount: number;
		subscriptionEquivUsd: number;
		subscriptionSessionCount: number;
		localSessionCount: number;
		localEstimatedUsd: number | null;
	};
}

export const load: PageLoad = async ({ params, fetch }) => {
	const client = createClient(fetch as unknown as typeof globalThis.fetch);
	const data = await client.request<SessionsResult>(SESSIONS_QUERY, {
		first: 100,
		projectId: params.projectId
	});
	const filteredEdges = data.agentSessions.edges.filter(
		(e) => e.node.projectId === params.projectId
	);
	return {
		nodeId: params.nodeId,
		projectId: params.projectId,
		sessions: {
			...data.agentSessions,
			edges: filteredEdges,
			totalCount: filteredEdges.length
		},
		costSummary: data.sessionsCostSummary
	};
};

package agent

import (
	"net"
	"net/netip"
	"net/url"
	"strings"
)

const (
	BillingModePaid         = "paid"
	BillingModeSubscription = "subscription"
	BillingModeLocal        = "local"
)

func ValidBillingMode(mode string) bool {
	switch mode {
	case BillingModePaid, BillingModeSubscription, BillingModeLocal:
		return true
	default:
		return false
	}
}

func BillingModeFor(harness, surface, baseURL string) string {
	h := strings.ToLower(strings.TrimSpace(harness))
	s := strings.ToLower(strings.TrimSpace(surface))

	if isLocalHarnessOrSurface(h) || isLocalHarnessOrSurface(s) {
		return BillingModeLocal
	}
	if isSubscriptionHarnessOrSurface(h) || isSubscriptionHarnessOrSurface(s) {
		return BillingModeSubscription
	}
	if isLocalBaseURL(baseURL) {
		return BillingModeLocal
	}
	return BillingModePaid
}

func billingModeForIndexEntry(entry SessionIndexEntry) string {
	if ValidBillingMode(entry.BillingMode) {
		return entry.BillingMode
	}
	return BillingModeFor(entry.Harness, entry.Surface, "")
}

func billingModeForLegacyEntry(entry SessionEntry) string {
	if ValidBillingMode(entry.BillingMode) {
		return entry.BillingMode
	}
	baseURL := firstNonEmpty(
		entry.ResolvedBaseURL,
		entry.CanonicalTarget,
		correlationValue(entry.Correlation, "resolved_base_url"),
		correlationValue(entry.Correlation, "base_url"),
	)
	return BillingModeFor(firstNonEmpty(entry.Harness, entry.Provider), entry.Surface, baseURL)
}

func isLocalHarnessOrSurface(value string) bool {
	switch value {
	case "agent", "virtual", "script", "lmstudio", "ollama", "vllm", "omlx", "local", "embedded-local":
		return true
	default:
		return false
	}
}

func isSubscriptionHarnessOrSurface(value string) bool {
	switch value {
	case "claude", "codex", "gemini", "gemini-cli":
		return true
	default:
		return false
	}
}

func isLocalBaseURL(raw string) bool {
	raw = strings.TrimSpace(raw)
	if raw == "" {
		return false
	}
	parsed, err := url.Parse(raw)
	if err != nil || parsed.Host == "" {
		parsed, err = url.Parse("http://" + raw)
		if err != nil {
			return false
		}
	}
	host := parsed.Hostname()
	if host == "" {
		if h, _, err := net.SplitHostPort(parsed.Host); err == nil {
			host = h
		} else {
			host = parsed.Host
		}
	}
	host = strings.Trim(strings.ToLower(host), "[]")
	switch host {
	case "", "localhost":
		return host == "localhost"
	}
	if !strings.Contains(host, ".") && !strings.Contains(host, ":") {
		return true
	}
	if addr, err := netip.ParseAddr(host); err == nil {
		return addr.IsLoopback() || addr.IsPrivate() || addr.IsLinkLocalUnicast()
	}
	return false
}

func correlationValue(correlation map[string]string, key string) string {
	if correlation == nil {
		return ""
	}
	return correlation[key]
}

