// SessionsCostSummary is the resolver for the sessionsCostSummary field.
func (r *queryResolver) SessionsCostSummary(ctx context.Context, projectID string, since *string, until *string) (*SessionsCostSummary, error) {
	var sinceTime *time.Time
	var untilTime *time.Time
	if since != nil && *since != "" {
		if parsed, err := time.Parse(time.RFC3339, *since); err == nil {
			sinceTime = &parsed
		}
	}
	if until != nil && *until != "" {
		if parsed, err := time.Parse(time.RFC3339, *until); err == nil {
			untilTime = &parsed
		}
	}
	proj, ok := r.State.GetProjectSnapshotByID(projectID)
	if !ok || proj == nil {
		return &SessionsCostSummary{}, nil
	}
	entries, err := agent.ReadSessionIndex(agent.SessionLogDirForWorkDir(proj.Path), agent.SessionIndexQuery{
		StartedAfter:  sinceTime,
		StartedBefore: untilTime,
		DefaultRecent: sinceTime == nil && untilTime == nil,
	})
	if err != nil {
		return &SessionsCostSummary{}, nil
	}
	var localRate *float64
	if cfg, err := ddxconfig.LoadWithWorkingDir(proj.Path); err == nil && cfg.Cost != nil {
		localRate = cfg.Cost.LocalPer1KTokens
	}
	summary := &SessionsCostSummary{}
	var localTokens int
	for _, entry := range entries {
		switch entry.BillingMode {
		case agent.BillingModePaid:
			summary.CashUsd += entry.CostUSD
			summary.CashSessionCount++
		case agent.BillingModeSubscription:
			summary.SubscriptionEquivUsd += entry.CostUSD
			summary.SubscriptionSessionCount++
		case agent.BillingModeLocal:
			summary.LocalSessionCount++
			localTokens += sessionTokenTotal(entry)
		default:
			switch agent.BillingModeFor(entry.Harness, entry.Surface, "") {
			case agent.BillingModeSubscription:
				summary.SubscriptionEquivUsd += entry.CostUSD
				summary.SubscriptionSessionCount++
			case agent.BillingModeLocal:
				summary.LocalSessionCount++
				localTokens += sessionTokenTotal(entry)
			default:
				summary.CashUsd += entry.CostUSD
				summary.CashSessionCount++
			}
		}
	}
	if localRate != nil {
		estimated := *localRate * float64(localTokens) / 1000
		summary.LocalEstimatedUsd = &estimated
	}
	return summary, nil
}

func sessionTokenTotal(entry agent.SessionIndexEntry) int {
	if entry.Tokens > 0 {
		return entry.Tokens
	}
	return entry.InputTokens + entry.OutputTokens
}

